                            ) {
                                profile.followers?.let {
                                    Column(horizontalAlignment = Alignment.CenterHorizontally) {
                                        Text(
                                            "$followerCount", // Uporabimo mutirano ≈°tevilko
                                            fontSize = 24.sp,
                                            fontWeight = FontWeight.Bold,
                                            color = accentGreen
                                        )
                                        Text(
                                            "Followers",
                                            fontSize = 12.sp,
                                            color = MaterialTheme.colorScheme.onSurfaceVariant
                                        )
                                    }
                                }

                                profile.following?.let {
                                    Column(horizontalAlignment = Alignment.CenterHorizontally) {
                                        Text(
                                            "$it",
                                            fontSize = 24.sp,
                                            fontWeight = FontWeight.Bold,
                                            color = accentBlue
                                        )
                                        Text(
                                            "Following",
                                            fontSize = 12.sp,
                                            color = MaterialTheme.colorScheme.onSurfaceVariant
                                        )
                                    }
                                }

                                profile.streak?.let {
                                    Column(horizontalAlignment = Alignment.CenterHorizontally) {
                                        Text(
                                            " $it",
                                            fontSize = 24.sp,
                                            fontWeight = FontWeight.Bold,
